function solve(n, edges, k) {
    if (edges.length === 0) {
        return 0;
    }

    let maxEdge = Math.max(...edges.map(e => e[2]));
    let sortedEdges = [...edges];
    sortedEdges.sort((a, b) => a[2] - b[2]);

    let low = 0;
    let high = maxEdge;
    let ans = -1;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let parent = new Array(n);
        let rank = new Array(n).fill(0);
        for (let i = 0; i < n; i++) {
            parent[i] = i;
        }

        const find = (x) => {
            if (parent[x] !== x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };

        const union = (x, y) => {
            let rx = find(x);
            let ry = find(y);
            if (rx === ry) {
                return false;
            }
            if (rank[rx] < rank[ry]) {
                parent[rx] = ry;
            } else if (rank[ry] < rank[rx]) {
                parent[ry] = rx;
            } else {
                parent[ry] = rx;
                rank[rx]++;
            }
            return true;
        };

        let comp = n;

        for (let i = 0; i < sortedEdges.length; i++) {
            let [u, v, w] = sortedEdges[i];
            if (w > mid) {
                break;
            }
            if (find(u) !== find(v)) {
                if (union(u, v)) {
                    comp--;
                }
            }
        }

        if (comp <= k) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return ans;
}
```

